import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Edge cases: empty / minimal ---
  it("empty item list -> premium 5 G (only processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });

  // --- Base premiums for each main item type (single item, newcomer 0 years, first contract) ---
  // Newcomer 0 years => first insurance surcharge (+10%) applies; no loyalty; first contract (no follow-up discount)
  it("single sword (steel, ench 3), newcomer -> 100 base + 10 first ins + 5 fee = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("single amulet (silver, ench 2), newcomer -> 60 base + 6 first ins + 5 fee = 71 G (rounded up in MHPCO favor)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("single staff, newcomer -> 80 base + 8 first ins + 5 fee = 93 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 93 }] });
  });
  it("single potion, newcomer -> 40 base + 4 first ins + 5 fee = 49 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 49 }] });
  });

  // --- Component pricing and building blocks of 3 ---
  it.todo("2 runes (base premium only, ignoring modifiers) -> 50 G base premium");
  it.todo("3 runes -> 60 G base premium (block applies)");
  it.todo("4 runes -> 100 G base premium (no block; block requires exactly 3)");
  it.todo("7 runes -> 175 G base premium (block requires exactly 3, no partial block)");

  // --- Alike components clarification (❓): same type, not same family ---
  it.todo("2 runes + 1 moonstone -> 75 G base premium (no block: different types)");
  it.todo("3 runes + 3 moonstones -> 120 G base premium (two separate blocks)");

  // --- Modifier scope on multi-item policies (❓) ---
  it.todo("cursed sword + plain amulet, newcomer -> per spec: base 160 + curse 50 = 210 before fee");

  // --- Modifier thresholds ---
  it.todo("customer with exactly 2 years -> loyalty discount applies");
  it.todo("sword with exactly enchantment 5 -> high-enchantment surcharge applies");
  it.todo("sword with enchantment 5 and cursed -> both surcharges apply");
  it.todo("sword with enchantment 4, not cursed -> no surcharges");

  // --- Rounding rule ---
  it.todo("premium yielding 197.5 G -> rounded UP to 198 G");

  // --- Integration examples ---
  it.todo("newcomer (0 years, 1st contract) with a cursed sword (steel ench 3) -> premium 165 G");
  it.todo("long-standing customer's second contract: cursed sword (steel ench 7), 3 years -> premium 160 G");

  // --- Claim: standard reimbursement (no special clauses) ---
  it.todo("regular sword steel ench 3, damage 500 G -> payout 400 G");
  it.todo("damage to a rune (insurance 250), damage 200 G -> payout 100 G");

  // --- Claim: enchantment threshold vs dragon material ---
  it.todo("dragon-material sword, exactly ench 8, damage 1000 -> payout 400 (50% rule then deductible)");
  it.todo("dragon-material sword, ench 9, damage 1000 -> payout 400 (50% wins, then deductible)");
  it.todo("dragon-material sword, ench 5, damage 800 -> payout 700 (dragon clause only, then deductible)");
  it.todo("steel sword, ench 9, damage 1000 -> payout 400 (high-ench only: 500 - 100)");

  // --- Claim: deductible per damage event (per item) ---
  it.todo("dragon attack damages sword (500) and amulet (300) -> payout 600 (deductible per item)");

  // --- Claim: multiple items of same type ---
  it.todo("policy with two swords -> insurance sum 2000, cap 4000");
  it.todo("policy with two swords; dragon attack damages both with two damage entries -> each entry has its own deductible");
  it.todo("damages array has more entries of a type than insured -> CLI rejects (non-zero exit), no results emitted for that claim");

  // --- Claim: cap exhaustion ---
  it.todo("sword + amulet policy -> insurance sum 1600, cap 3200");
  it.todo("cursed sword (premium with modifiers 165) -> cap 2000 (based on unmodified insurance value)");
  it.todo("sword + 3 runes (block) -> insurance sum 1750 (block affects premium only, not insurance sum)");
  it.todo("sword (cap 2000), two successive claims of 1500 each -> 1st payout 1400 (remaining 600), 2nd payout 600 (remaining 0)");

  // --- Rounding direction for payout ---
  it.todo("payout yielding 350.5 G -> rounded DOWN to 350 G");

  // --- Error cases (CLI level) ---
  it.todo("quote includes unknown item type (e.g. broomstick) -> CLI exits non-zero, writes error to stderr, no results to stdout");
  it.todo("claim references damage on an item not in policy (amulet damaged but only sword insured) -> CLI exits non-zero");
  it.todo("claim references damage on an unknown item type -> CLI exits non-zero");
  it.todo("claim contains damage entry with amount: -200 -> CLI exits non-zero, writes error to stderr");
});

