const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
type QuoteResult = { premium: number };
type ScenarioResult = { results: QuoteResult[] };

const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;

const itemBasePremium = (item: Item): number => BASE_PREMIUM[item.type];

const isBlockOfThreeRunes = (items: Item[]): boolean =>
  items.length === COMPONENT_BLOCK_SIZE &&
  items.every((item) => item.type === "rune");

const policyBasePremium = (items: Item[]): number => {
  if (isBlockOfThreeRunes(items)) {
    return COMPONENT_BLOCK_PREMIUM;
  }
  return items.reduce((sum, item) => sum + itemBasePremium(item), 0);
};

const quotePremium = (items: Item[]): number => {
  const basePremium = policyBasePremium(items);
  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
  return basePremium + firstInsuranceSurcharge + PROCESSING_FEE;
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
  return { results };
};

