const policyInsuranceSum = (items: Item[]): number =>
  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);

const claimPayout = (damages: Damage[]): number =>
  damages.reduce((sum, d) => sum + (d.amount - DEDUCTIBLE), 0);

export const runScenario = (scenario: Scenario): ScenarioResult => {
  let quoteCount = 0;
  const policies: Item[][] = [];
  const results: StepResult[] = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const isFollowUp = quoteCount > 0;
      quoteCount += 1;
      policies.push(step.items);
      return {
        premium: Math.ceil(quotePremium(step.items, scenario.customer, isFollowUp)),
      };
    }
    const items = policies[step.policy];
    const payout = claimPayout(step.incident.damages);
    const cap = policyInsuranceSum(items) * CAP_MULTIPLIER;
    return { payout, remainingCap: cap - payout };
  });
  return { results };
};

