  items: Item[],
  incident: Incident,
  remainingCap: number,
): ClaimResult => {
  validateDamageCounts(items, incident.damages);
  const rawPayout = claimPayout(items, incident.damages);
  const payout = Math.min(rawPayout, remainingCap);
  return { payout, remainingCap: remainingCap - payout };
};

